import React, { useState, useEffect, useCallback } from "react";
import { getAllConnections, getAllSensors } from "../api/adminService"; // ← getAllUsers removed
import api from "../api/axiosInstance";
 
// ─── helpers ──────────────────────────────────────────────────────────────────
function toArray(d) {
  if (Array.isArray(d)) return d;
  if (d?.data   && Array.isArray(d.data))   return d.data;
  if (d?.items  && Array.isArray(d.items))  return d.items;
  if (d?.result && Array.isArray(d.result)) return d.result;
  return [];
}
 
// ─── Read current user from localStorage + JWT (no API call needed) ───────────
// Your app already stores: sb_userId=10, sb_username=abcd, sb_role=admin
// JWT payload has: sub, name, email, role claim
function parseJwt(token) {
  try {
    return JSON.parse(atob(token.split(".")[1].replace(/-/g,"+").replace(/_/g,"/")));
  } catch { return {}; }
}
 
function getCurrentUserFromStorage() {
  const token   = localStorage.getItem("sb_access_token") || "";
  const payload = parseJwt(token);
  const userId  = localStorage.getItem("sb_userId") || payload?.sub;
  if (!userId) return null;
  return {
    userId:   Number(userId),
    fullName: localStorage.getItem("sb_username") || payload?.name || "Unknown",
    username: localStorage.getItem("sb_username") || payload?.name || "Unknown",
    email:    payload?.email || "",
    userRole: localStorage.getItem("sb_role")
              || payload?.["http://schemas.microsoft.com/ws/2008/06/identity/claims/role"]
              || "User",
    createdAt: null,
  };
}
 
// ─── Avatar ───────────────────────────────────────────────────────────────────
const PAL = [
  { bg:"#dbeafe", fg:"#1d4ed8" }, { bg:"#dcfce7", fg:"#15803d" },
  { bg:"#fef9c3", fg:"#a16207" }, { bg:"#fce7f3", fg:"#9d174d" },
  { bg:"#ede9fe", fg:"#6d28d9" }, { bg:"#ccfbf1", fg:"#0f766e" },
];
function Avatar({ name="?", size=38 }) {
  const ini = name.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase();
  const c = PAL[name.charCodeAt(0) % PAL.length];
  return (
<div style={{ width:size, height:size, borderRadius:"50%", background:c.bg, color:c.fg,
      display:"flex", alignItems:"center", justifyContent:"center",
      fontWeight:600, fontSize:size*0.34, flexShrink:0, userSelect:"none" }}>
      {ini}
</div>
  );
}
 
// ─── StatusBadge ──────────────────────────────────────────────────────────────
function StatusBadge({ status }) {
  const label = status === true  || status === "true"  ? "Active"
              : status === false || status === "false" ? "Inactive"
              : status ?? "Active";
  const map = {
    Active:   { bg:"#dcfce7", color:"#15803d" },
    Inactive: { bg:"#f1f5f9", color:"#64748b" },
    Pending:  { bg:"#fef9c3", color:"#a16207" },
    Error:    { bg:"#fee2e2", color:"#b91c1c" },
  };
  const s = map[label] || map.Active;
  return (
<span style={{ background:s.bg, color:s.color, fontSize:12,
      fontWeight:600, padding:"2px 10px", borderRadius:20 }}>{label}</span>
  );
}
 
// ─── RoleBadge ────────────────────────────────────────────────────────────────
function RoleBadge({ role }) {
  const isAdmin = role?.toLowerCase() === "admin";
  return (
<span style={{
      background: isAdmin ? "#ede9fe" : "#f1f5f9",
      color:      isAdmin ? "#6d28d9" : "#64748b",
      fontSize:11, fontWeight:600, padding:"2px 8px", borderRadius:20,
    }}>{role ?? "User"}</span>
  );
}
 
// ─── Connections tab ──────────────────────────────────────────────────────────
function ConnectionsTab({ userId }) {
  const [rows, setRows] = useState(null);
  const [err, setErr]   = useState(null);
 
  useEffect(() => {
    if (!userId) return;
    setRows(null); setErr(null);
    api.get(`/api/Connections/user/${userId}`)
      .then(r => setRows(toArray(r.data)))
      .catch(e => { setErr(e?.response?.data?.message || "Failed to load."); setRows([]); });
  }, [userId]);
 
  if (rows === null) return <p className="text-muted small p-3">Loading…</p>;
  if (err)           return <p className="text-danger small p-3">{err}</p>;
  if (!rows.length)  return <p className="text-muted small p-3">No connections for this user.</p>;
 
  return (
<div className="table-responsive">
<table className="table table-sm mb-0" style={{ fontSize:14 }}>
<thead>
<tr style={{ borderBottom:"1px solid var(--sb-border)" }}>
            {["Name","URL","Port","Protocol","TLS","Status"].map(h => (
<th key={h} className="text-muted small py-2 px-3"
                style={{ background:"var(--sb-card-bg)", fontWeight:500 }}>{h}</th>
            ))}
</tr>
</thead>
<tbody>
          {rows.map((c,i) => (
<tr key={c.connectionId ?? i} style={{ borderBottom:"1px solid var(--sb-border)" }}>
<td className="py-2 px-3 fw-semibold">{c.connectionName ?? c.name ?? "—"}</td>
<td className="py-2 px-3 text-muted" style={{ fontFamily:"monospace", fontSize:12 }}>
                {c.connectionUrl ?? c.url ?? "—"}
</td>
<td className="py-2 px-3">{c.port ?? "—"}</td>
<td className="py-2 px-3">{c.protocol ?? "—"}</td>
<td className="py-2 px-3">{c.tlsEnabled ? "Yes" : "No"}</td>
<td className="py-2 px-3"><StatusBadge status={c.isActive ?? true} /></td>
</tr>
          ))}
</tbody>
</table>
</div>
  );
}
 
// ─── Sensors tab ─────────────────────────────────────────────────────────────
function SensorsTab({ userId }) {
  const [rows, setRows] = useState(null);
  const [err, setErr]   = useState(null);
 
  useEffect(() => {
    if (!userId) return;
    setRows(null); setErr(null);
    api.get(`/api/Sensors/user/${userId}`)
      .then(r => setRows(toArray(r.data)))
      .catch(e => { setErr(e?.response?.data?.message || "Failed to load."); setRows([]); });
  }, [userId]);
 
  if (rows === null) return <p className="text-muted small p-3">Loading…</p>;
  if (err)           return <p className="text-danger small p-3">{err}</p>;
  if (!rows.length)  return <p className="text-muted small p-3">No sensors for this user.</p>;
 
  return (
<div className="table-responsive">
<table className="table table-sm mb-0" style={{ fontSize:14 }}>
<thead>
<tr style={{ borderBottom:"1px solid var(--sb-border)" }}>
            {["Name","Quantity","Unit","Topic","Location","Status"].map(h => (
<th key={h} className="text-muted small py-2 px-3"
                style={{ background:"var(--sb-card-bg)", fontWeight:500 }}>{h}</th>
            ))}
</tr>
</thead>
<tbody>
          {rows.map((s,i) => (
<tr key={s.sensorId ?? i} style={{ borderBottom:"1px solid var(--sb-border)" }}>
<td className="py-2 px-3 fw-semibold">{s.sensorName ?? "—"}</td>
<td className="py-2 px-3 text-muted">{s.quantity ?? "—"}</td>
<td className="py-2 px-3 text-muted">{s.unit ?? "—"}</td>
<td className="py-2 px-3 text-muted" style={{ fontFamily:"monospace", fontSize:12 }}>
                {s.topicName ?? "—"}
</td>
<td className="py-2 px-3 text-muted">{s.locatedAt ?? "—"}</td>
<td className="py-2 px-3"><StatusBadge status={s.isActive} /></td>
</tr>
          ))}
</tbody>
</table>
</div>
  );
}
 
// ─── User detail panel ────────────────────────────────────────────────────────
const TABS = ["Connections","Sensors","KPIs","Dashboard data","Deleted items"];
 
function UserDetail({ user, onEdit, onDelete }) {
  const [tab, setTab] = useState("Connections");
  useEffect(() => setTab("Connections"), [user?.userId]);
 
  if (!user) return (
<div className="d-flex align-items-center justify-content-center flex-grow-1 text-muted small">
      Select a user to view details
</div>
  );
 
  const displayName = user.fullName || user.username || "Unknown";
  const joined = user.createdAt
    ? new Date(user.createdAt).toLocaleDateString("en-US", { month:"short", year:"numeric" })
    : "—";
 
  return (
<div className="d-flex flex-column flex-grow-1" style={{ minWidth:0 }}>
<div className="d-flex align-items-center gap-3 flex-wrap p-3"
        style={{ borderBottom:"1px solid var(--sb-border)", rowGap:10 }}>
<Avatar name={displayName} size={46} />
<div className="flex-grow-1" style={{ minWidth:0 }}>
<div className="fw-semibold d-flex align-items-center gap-2" style={{ fontSize:15 }}>
            {displayName}
<RoleBadge role={user.userRole} />
</div>
<div className="small text-muted">{user.email} · joined {joined}</div>
</div>
<div className="d-flex gap-2">
<button onClick={() => onEdit(user)}
            className="btn btn-sm btn-outline-secondary" style={{ fontSize:13 }}>Edit user</button>
<button onClick={() => onDelete(user)}
            className="btn btn-sm"
            style={{ fontSize:13, border:"1px solid #b91c1c", color:"#b91c1c", background:"transparent" }}>
            Delete
</button>
</div>
</div>
 
      <div className="d-flex px-3" style={{ borderBottom:"1px solid var(--sb-border)", overflowX:"auto" }}>
        {TABS.map(t => (
<button key={t} onClick={() => setTab(t)} style={{
            padding:"10px 14px", fontSize:13, background:"none", border:"none", cursor:"pointer",
            borderBottom: tab===t ? "2px solid var(--sb-accent)" : "2px solid transparent",
            color: tab===t ? "var(--sb-accent)" : "var(--sb-muted)",
            fontWeight: tab===t ? 600 : 400, whiteSpace:"nowrap", flexShrink:0,
          }}>{t}</button>
        ))}
</div>
 
      <div style={{ flex:1, overflowY:"auto" }}>
        {tab === "Connections"    && <ConnectionsTab userId={user.userId} />}
        {tab === "Sensors"        && <SensorsTab     userId={user.userId} />}
        {tab === "KPIs"           && <p className="text-muted small p-3">KPI data will appear here.</p>}
        {tab === "Dashboard data" && <p className="text-muted small p-3">Dashboard data will appear here.</p>}
        {tab === "Deleted items"  && <p className="text-muted small p-3">No deleted items.</p>}
</div>
</div>
  );
}
 
// ─── Edit modal ───────────────────────────────────────────────────────────────
function EditModal({ user, onClose, onSave }) {
  const [fullName, setFullName] = useState(user.fullName || "");
  const [email, setEmail]       = useState(user.email || "");
  const [saving, setSaving]     = useState(false);
  const [err, setErr]           = useState(null);
 
  const save = async () => {
    setSaving(true); setErr(null);
    try {
      await api.put(`/api/Users/${user.userId}`, { fullName, email });
      onSave({ ...user, fullName, email });
    } catch(e) { setErr(e?.response?.data?.message || "Update failed."); }
    finally { setSaving(false); }
  };
 
  return (
<div className="modal d-block" tabIndex="-1"
      style={{ background:"rgba(0,0,0,0.4)" }} onClick={onClose}>
<div className="modal-dialog modal-dialog-centered" onClick={e => e.stopPropagation()}>
<div className="modal-content border-0 shadow"
          style={{ borderRadius:12, background:"var(--sb-card-bg)" }}>
<div className="modal-header border-0 pb-0">
<h6 className="modal-title fw-semibold">Edit user</h6>
<button className="btn-close" onClick={onClose} />
</div>
<div className="modal-body">
            {[["Full name", fullName, setFullName],["Email", email, setEmail]].map(([lbl,val,set]) => (
<div key={lbl} className="mb-3">
<label className="form-label small text-muted">{lbl}</label>
<input value={val} onChange={e => set(e.target.value)}
                  className="form-control sb-input" style={{ fontSize:14 }} />
</div>
            ))}
            {err && <div className="alert alert-danger py-2 small">{err}</div>}
</div>
<div className="modal-footer border-0 pt-0">
<button className="btn btn-sm btn-outline-secondary" onClick={onClose}>Cancel</button>
<button className="btn btn-sm sb-primary-btn" onClick={save} disabled={saving}>
              {saving ? "Saving…" : "Save"}
</button>
</div>
</div>
</div>
</div>
  );
}
 
// ─── ManagementPage ───────────────────────────────────────────────────────────
const ManagementPage = () => {
  const [users, setUsers]           = useState([]);
  const [allConns, setAllConns]     = useState([]);
  const [allSensors, setAllSensors] = useState([]);
  const [selected, setSelected]     = useState(null);
  const [search, setSearch]         = useState("");
  const [loading, setLoading]       = useState(true);
  const [fetchErr, setFetchErr]     = useState(null);
  const [editing, setEditing]       = useState(null);
 
  useEffect(() => {
    if (!localStorage.getItem("sb_access_token")) window.location.href = "/login";
  }, []);
 
  const load = useCallback(async () => {
    setLoading(true); setFetchErr(null);
    try {
      // ── STEP 1: build user from localStorage — zero API calls needed ────────
      const currentUser = getCurrentUserFromStorage();
      if (!currentUser) { window.location.href = "/login"; return; }
      setUsers([currentUser]);
      setSelected(currentUser);
 
      // ── STEP 2: fetch global stats in parallel ──────────────────────────────
      const [cRes, sRes] = await Promise.all([
        getAllConnections(),
        getAllSensors(),
      ]);
      setAllConns(toArray(cRes.data));
      setAllSensors(toArray(sRes.data));
 
    } catch(e) {
      setFetchErr(e?.response?.data?.message || e.message || "Failed to load data.");
    } finally { setLoading(false); }
  }, []);
 
  useEffect(() => { load(); }, [load]);
 
  const activeConns = allConns.filter(c => c.isActive !== false).length;
  const activeSens  = allSensors.filter(s => s.isActive === true).length;
  const pending     = allConns.filter(c => c.deleted === true).length;
 
  const filtered = users.filter(u =>
    (u.fullName || "").toLowerCase().includes(search.toLowerCase()) ||
    (u.username || "").toLowerCase().includes(search.toLowerCase()) ||
    (u.email    || "").toLowerCase().includes(search.toLowerCase())
  );
 
  const handleEditSave = updated => {
    setUsers(prev => prev.map(u => u.userId === updated.userId ? updated : u));
    if (selected?.userId === updated.userId) setSelected(updated);
    setEditing(null);
  };
 
  const handleDelete = async user => {
    if (!window.confirm(`Delete "${user.fullName || user.username}"? This cannot be undone.`)) return;
    try {
      await api.delete(`/api/Users/${user.userId}`);
      setUsers(prev => {
        const next = prev.filter(u => u.userId !== user.userId);
        if (selected?.userId === user.userId) setSelected(next[0] ?? null);
        return next;
      });
    } catch(e) { alert(e?.response?.data?.message || "Delete failed."); }
  };
 
  return (
<div style={{ color:"var(--sb-text)" }}>
      {editing && <EditModal user={editing} onClose={() => setEditing(null)} onSave={handleEditSave} />}
 
      <div className="sb-page-header px-4 py-3 mb-4">
<h5 className="sb-header-title mb-1">
<i className="bi bi-people me-2 sb-accent"></i>Management
</h5>
<p className="sb-header-subtitle mb-0">Admin panel — users, connections &amp; sensors</p>
</div>
 
      <div className="px-4">
        {fetchErr && (
<div className="alert alert-danger py-2 small mb-3">
            {fetchErr} — <span style={{ cursor:"pointer", textDecoration:"underline" }} onClick={load}>retry</span>
</div>
        )}
 
        {/* Stat cards */}
<div className="row g-3 mb-4">
          {[
            { label:"Total users",        val: users.length },
            { label:"Active connections", val: activeConns },
            { label:"Active sensors",     val: activeSens },
            { label:"Deleted (pending)",  val: pending, danger:true },
          ].map(({ label, val, danger }) => (
<div key={label} className="col-6 col-md-3">
<div className="card border-0 shadow-sm p-3"
                style={{ borderRadius:12, background:"var(--sb-card-bg)" }}>
<div className="small text-muted mb-1">{label}</div>
<div style={{ fontSize:28, fontWeight:700,
                  color: danger ? "#b91c1c" : "var(--sb-text)" }}>
                  {loading ? "—" : val}
</div>
</div>
</div>
          ))}
</div>
 
        {/* Split panel */}
<div className="card border-0 shadow-sm d-flex flex-row"
          style={{ borderRadius:12, overflow:"hidden", minHeight:520, background:"var(--sb-card-bg)" }}>
 
          {/* Sidebar */}
<div style={{ width:260, flexShrink:0, borderRight:"1px solid var(--sb-border)", display:"flex", flexDirection:"column" }}>
<div className="p-2">
<input type="text" placeholder="Search users…" value={search}
                onChange={e => setSearch(e.target.value)}
                className="form-control sb-input" style={{ fontSize:13 }} />
</div>
<div style={{ overflowY:"auto", flex:1 }}>
              {loading ? (
<p className="text-muted small text-center p-3">Loading…</p>
              ) : filtered.length === 0 ? (
<p className="text-muted small text-center p-3">No users found.</p>
              ) : filtered.map(u => {
                const isActive = selected?.userId === u.userId;
                const displayName = u.fullName || u.username || "Unknown";
                return (
<div key={u.userId} onClick={() => setSelected(u)} style={{
                    display:"flex", alignItems:"center", gap:10,
                    padding:"10px 14px", cursor:"pointer",
                    background: isActive ? "var(--sb-light-bg)" : "transparent",
                    borderLeft: isActive ? "3px solid var(--sb-accent)" : "3px solid transparent",
                  }}>
<Avatar name={displayName} size={36} />
<div style={{ minWidth:0 }}>
<div style={{ fontWeight:600, fontSize:13, whiteSpace:"nowrap",
                        overflow:"hidden", textOverflow:"ellipsis" }}>{displayName}</div>
<div className="text-muted" style={{ fontSize:11 }}>
                        {u.userRole ?? "user"} · ID {u.userId}
</div>
</div>
</div>
                );
              })}
</div>
</div>
 
          <UserDetail user={selected} onEdit={setEditing} onDelete={handleDelete} />
</div>
</div>
</div>
  );
};
 
export default ManagementPage;
